sql:
SELECT fuel_name, MAX(octane_rating) AS max_octane_rating 
FROM fuel_types 
GROUP BY fuel_name;

SELECT COUNT(*)
FROM drive_wheels
WHERE drive_configuration = 'fwd';

SELECT drive_configuration, description
FROM drive_wheels
WHERE drivetrain_type = 'rear-wheel drive';

SELECT vehicle_id 
FROM recalls 
WHERE resolved = 0;

SELECT COUNT(vehicle_id)
FROM safety_ratings
WHERE rating_agency = 'NHTSA';

